-- II B.COM / A&F
INSERT INTO student_session (session_id, student_id, class_id, section_id, is_active, is_alumni)
  SELECT 22, s.id, cs.class_id, cs.section_id, 'yes', 0
  FROM students s
  JOIN classes c   ON LOWER(c.class)   = LOWER('II B.COM')
  JOIN sections sec ON LOWER(sec.section) = LOWER('A&F')
  JOIN class_sections cs ON cs.class_id=c.id AND cs.section_id=sec.id
  WHERE s.note='IMP_MAASC_2026' AND s.admission_no IN (
    '474', '1741', '1740', '2064', '2076', '1797', '1739'
  )
  AND NOT EXISTS (
    SELECT 1 FROM student_session ss2
    WHERE ss2.session_id=22 AND ss2.student_id=s.id
  );

